#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y) {

    // Parallelise the outer loop (each iteration is independent)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sumA = 0.0, sumB = 0.0;
        const std::vector<double>& Arow = A[i];
        const std::vector<double>& Brow = B[i];
        // Loop over j
        for (int j = 0; j < n; ++j) {
            double xj = x[j];
            sumA += Arow[j] * xj;
            sumB += Brow[j] * xj;
        }
        tmp[i] = sumA;
        y[i]   = alpha * sumA + beta * sumB;
    }
}
