void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B)
{
    // Ensure we have enough elements
    if (n <= 2) return;

    const double coef = 0.33333;
    const std::size_t n_minus_1 = static_cast<std::size_t>(n - 1);

    // Use raw pointers for fast indexed access
    double* restrict a = A.data();
    double* restrict b = B.data();

    for (int t = 0; t < tsteps; ++t) {
        // First update: B depends only on old A
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 1; i < n_minus_1; ++i) {
            b[i] = coef * (a[i-1] + a[i] + a[i+1]);
        }

        // Second update: A depends only on new B
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 1; i < n_minus_1; ++i) {
            a[i] = coef * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
