#include <vector>
#include <cstddef>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>> &A,
                 std::vector<std::vector<double>> &B,
                 std::vector<std::vector<double>> &C)
{
    /*  Blas‑style GEMM:  C ← α·A·B + β·C
        A : ni × nk
        B : nk × nj
        C : ni × nj
    */

    /* Parallelise over the outermost dimension `i` which is independent
       of all other work. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *c_row = C[i].data();        // row of C
        const double *a_row = A[i].data();  // row of A

        /* Scale the row by β first. */
        for (int j = 0; j < nj; ++j)
            c_row[j] *= beta;

        /* Accumulate contributions from each k. */
        for (int k = 0; k < nk; ++k) {
            double a_val = alpha * a_row[k];
            const double *b_row = B[k].data();   // kth row of B (since B is NK×NJ)
            for (int j = 0; j < nj; ++j)
                c_row[j] += a_val * b_row[j];
        }
    }
}
