/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
    /* Parallelise the outer loop: each iteration only uses
       rows < i, which are already computed by previous iterations. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* Off‑diagonal elements */
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            // Compute dot product A[i][0..j-1] * A[j][0..j-1]
            for (int k = 0; k < j; ++k) {
                sum += A[i][k] * A[j][k];
            }
            A[i][j] = (A[i][j] - sum) / A[j][j];
        }

        /* Diagonal element */
        double diag = A[i][i];
        for (int k = 0; k < i; ++k) {
            diag -= A[i][k] * A[i][k];
        }
        A[i][i] = std::sqrt(diag);
    }
}
