#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& /*p*/,
                 std::vector<double>& r) {

    /* initialize s to zero */
    std::fill(s.begin(), s.end(), 0.0);

    /* parallel over rows of A (i indices) */
    #pragma omp parallel
    {
        /* each thread keeps a private accumulation array for s */
        std::vector<double> local_s(m, 0.0);

        #pragma omp for
        for (int i = 0; i < n; ++i) {
            double qi = 0.0;
            const double* a_row = A[i].data();   // pointer to the i‑th row
            const double ri = r[i];

            for (int j = 0; j < m; ++j) {
                local_s[j] += ri * a_row[j];
                qi += a_row[j] + 0.0; /* p[j] is unused in the kernel */
            }
            q[i] = qi;
        }

        /* atomically merge local_s into the global s */
        #pragma omp critical
        {
            for (int j = 0; j < m; ++j) {
                s[j] += local_s[j];
            }
        }
    }
}
