/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    // *******************************
    // 1. Rank‑2 update of A
    // *******************************
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double u1i = u1[i];
        double u2i = u2[i];
        std::vector<double>& Ai = A[i];
        for (int j = 0; j < n; ++j) {
            Ai[j] += u1i * v1[j] + u2i * v2[j];
        }
    }

    // *******************************
    // 2. Update x using A^T
    // *******************************
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double xi = x[i];
        for (int j = 0; j < n; ++j) {
            xi += beta * A[j][i] * y[j];
        }
        x[i] = xi + z[i];   // combine last two loop passes
    }

    // *******************************
    // 3. Final update of w
    // *******************************
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double wi = w[i];
        const std::vector<double>& Ai = A[i];
        for (int j = 0; j < n; ++j) {
            wi += alpha * Ai[j] * x[j];
        }
        w[i] = wi;
    }
