/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    // Zero y (parallel, no data dependency)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) y[i] = 0.0;

    // Parallel outer loop with per-thread local y buffer
    int num_threads = omp_get_max_threads();
    std::vector<std::vector<double>> y_local(num_threads, std::vector<double>(n, 0.0));

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::vector<double> &y_buf = y_local[tid];

        #pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            double *Ai = A[i].data();
            double sum = 0.0;

            // Compute tmp[i] = Ai * x (dot product)
            #pragma omp simd reduction(+:sum)
            for (int j = 0; j < n; ++j) {
                sum += Ai[j] * x[j];
            }
            tmp[i] = sum;

            // Accumulate contribution to y in thread-local buffer
            #pragma omp simd
            for (int j = 0; j < n; ++j) {
                y_buf[j] += Ai[j] * sum;
            }
        }
    }

    // Reduce thread-local y buffers into final y
    for (int t = 0; t < num_threads; ++t) {
        const std::vector<double> &y_buf = y_local[t];
        for (int j = 0; j < n; ++j) y[j] += y_buf[j];
    }
}
