#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    // BLAS PARAMS
    // UPLO  = 'L'
    // TRANS = 'N'
    // A is NxM
    // B is NxM
    // C is NxN

    const double a_alpha = alpha;
    const double b_beta  = beta;

    // Parallelise the `i` loop – the iterations are independent.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        std::vector<double> *Ci = &C[i];      // pointer to the current row of C
        std::vector<double> *Ai = &A[i];      // pointer to the current row of A
        std::vector<double> *Bi = &B[i];      // pointer to the current row of B

        // scale the lower triangular part of C[i][j] by beta
        for (int j = 0; j <= i; ++j)
            (*Ci)[j] *= b_beta;

        // iterate over the shared dimension `k`
        for (int k = 0; k < m; ++k) {
            double aik = (*Ai)[k] * a_alpha;          // A[i][k] * alpha
            double bik = (*Bi)[k] * a_alpha;          // B[i][k] * alpha

            // accumulate contributions for all j <= i
            for (int j = 0; j <= i; ++j) {
                double val = (*C[i][j] += (*A[j])[k] * bik + (*B[j])[k] * aik);
                (*Ci)[j] = val;      // write back (not strictly necessary, keeps compiler happy)
            }
        }
    }
}
