/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
                std::vector<std::vector<double>>& E,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& F,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D,
                std::vector<std::vector<double>>& G)
{
    /* Compute E = A * B  (ni × nj)                */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* Ei = E[i].data();
        const double* Ai = A[i].data();
        for (int k = 0; k < nk; ++k) {
            double aik = Ai[k];
            const double* Bk = B[k].data();
            for (int j = 0; j < nj; ++j) {
                Ei[j] += aik * Bk[j];
            }
        }
    }

    /* Compute F = C * D  (nj × nl)                */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < nj; ++i) {
        double* Fi = F[i].data();
        const double* Ci = C[i].data();
        for (int k = 0; k < nm; ++k) {
            double cik = Ci[k];
            const double* Dk = D[k].data();
            for (int j = 0; j < nl; ++j) {
                Fi[j] += cik * Dk[j];
            }
        }
    }

    /* Compute G = E * F  (ni × nl)                */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* Gi = G[i].data();
        const double* Ei = E[i].data();
        for (int k = 0; k < nj; ++k) {
            double ek = Ei[k];
            const double* Fk = F[k].data();
            for (int j = 0; j < nl; ++j) {
                Gi[j] += ek * Fk[j];
            }
        }
    }
