/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {

    // Inline match function to avoid branching overhead.
    auto match = [](int b1, int b2) noexcept -> int
    { return (b1 + b2 == 3) ? 1 : 0; };

    /* The algorithm fills the table for increasing interval length.
       For each length, rows are independent and can be computed in parallel. */
    for (int len = 2; len <= n; ++len) {

        // Parallelize over the starting index i of each interval.
        #pragma omp parallel for schedule(static)
        for (int i = 0; i <= n - len; ++i) {
            int j = i + len - 1;

            int best = table[i][j];        // existing value (all zeros initially)

            // Neighbor intervals
            if (j - 1 >= 0)
                best = std::max(best, table[i][j - 1]);

            if (i + 1 < n)
                best = std::max(best, table[i + 1][j]);

            // Pairing i and j
            if (j - 1 >= 0 && i + 1 < n) {
                if (i < j - 1)
                    best = std::max(best, table[i + 1][j - 1] + match(seq[i], seq[j]));
                else
                    best = std::max(best, table[i + 1][j - 1]);
            }

            // Split point k
            for (int k = i + 1; k < j; ++k) {
                int val = table[i][k] + table[k + 1][j];
                if (val > best) best = val;
            }

            table[i][j] = best;
        }
    }
}
