/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // We keep the original calling convention, but inside we access
    // the 2‑D vectors as 1‑D blocks to improve cache usage and enable
    // better vectorization.  All the indices are computed by hand.
    const size_t mn = static_cast<size_t>(m) * static_cast<size_t>(n);
    const size_t mm  = static_cast<size_t>(m) * static_cast<size_t>(m);

    // Flatten the input matrices into raw arrays.
    // Note: we do *not* copy the data; we just get a pointer to the first
    // element of each vector-of-vectors.  This preserves the exact layout.
    double *C_raw = &C[0][0];
    double *A_raw = &A[0][0];
    double *B_raw = &B[0][0];

    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            const double Bij = B_raw[(size_t)i * n + j];
            const double Aii  = A_raw[(size_t)i * m + i];

            // Accumulate the lower triangular part
            for (int k = 0; k < i; ++k) {          // < i for symmetry
                const size_t ckj = (size_t)k * n + j;
                const size_t aik = (size_t)i * m + k;
                const double Bkj = B_raw[(size_t)k * n + j];
                C_raw[ckj] += alpha * Bij * A_raw[aik];
                temp2 += Bkj * A_raw[aik];
            }

            const size_t ij = (size_t)i * n + j;
            C_raw[ij] = beta * C_raw[ij] + alpha * Bij * Aii + alpha * temp2;
        }
    }
}
