#include <vector>
#include <cstddef>
#include <omp.h>
#include <cassert>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(
    int n,
    std::vector<std::vector<double>>& A,
    std::vector<double>& b,
    std::vector<double>& x,
    std::vector<double>& y)
{
    // Flatten A for faster indexing
    std::vector<double> flat(n * n);
    for (int i = 0; i < n; ++i)
    {
        std::memcpy(&flat[i * n], A[i].data(), n * sizeof(double));
    }

    /* LU decomposition with partial pivoting omitted (exact behavior) */
    for (int i = 0; i < n; ++i)
    {
        /* Compute lower triangle (L part) */
        for (int j = 0; j < i; ++j)
        {
            double w = flat[i * n + j];
            for (int k = 0; k < j; ++k)
            {
                w -= flat[i * n + k] * flat[k * n + j];
            }
            flat[i * n + j] = w / flat[j * n + j];
        }

        /* Compute upper triangle (U part) */
        for (int j = i; j < n; ++j)
        {
            double w = flat[i * n + j];
            for (int k = 0; k < i; ++k)
            {
                w -= flat[i * n + k] * flat[k * n + j];
            }
            flat[i * n + j] = w;
        }
    }

    /* Forward substitution (L * y = b) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        double w = b[i];
        for (int j = 0; j < i; ++j)
        {
            w -= flat[i * n + j] * y[j];
        }
        y[i] = w;
    }

    /* Backward substitution (U * x = y) */
    #pragma omp parallel for schedule(static)
    for (int ii = n - 1; ii >= 0; --ii)
    {
        int i = ii;
        double w = y[i];
        for (int j = i + 1; j < n; ++j)
        {
            w -= flat[i * n + j] * x[j];
        }
        x[i] = w / flat[i * n + i];
    }

    /* Write back the flattened matrix to the original structure */
    for (int i = 0; i < n; ++i)
    {
        std::memcpy(A[i].data(), &flat[i * n], n * sizeof(double));
    }
}
