// The harness calls this function with the same signature.
void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    // ------------------------------------------------------------------
    // 1.  Compute the column means.
    // ------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / static_cast<double>(n);
    }

    // ------------------------------------------------------------------
    // 2.  Center the data set in place.
    // ------------------------------------------------------------------
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            data[i][j] -= mean[j];

    // ------------------------------------------------------------------
    // 3.  Compute covariance matrix using a concurrent rewrite of the
    //     classic outer‑product algorithm.  The lower‑triangle is
    //     computed first; the upper‑triangle is filled by symmetry.
    // ------------------------------------------------------------------
    //    Each thread updates a private buffer for its chunk of rows to
    //    avoid false sharing.  After the parallel region the private
    //    buffers are summed into the global matrix.
    //
    //    We use a flat 1‑D buffer of size m*m for the local accumulators
    //    because cache‑line padded std::vector<std::vector> may suffer
    //    from poor locality when dim is large.
    const size_t LM = static_cast<size_t>(m);
    const size_t LM2 = LM * LM;

    std::vector<double> local(LM2, 0.0);

    #pragma omp parallel
    {
        int thread_id = omp_get_thread_num();
        // local copy for this thread
        std::vector<double> buf(LM2, 0.0);

        #pragma omp for schedule(static)
        for (int i = 0; i < n; ++i) {
            for (int a = 0; a < m; ++a) {
                double va = data[i][a];
                for (int b = a; b < m; ++b) {
                    buf[a*LM + b] += va * data[i][b];
                }
            }
        }

        // Combine local buffer into global `local`
        #pragma omp critical
        {
            for (size_t idx = 0; idx < LM2; ++idx)
                local[idx] += buf[idx];
        }
    }

    // Normalize and copy results into the symmetric matrix
    const double inv = 1.0 / static_cast<double>(n - 1);
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double val = local[i*LM + j] * inv;
            cov[i][j] = val;
            cov[j][i] = val;
        }
    }
