/* --------------------------------------------------------------------
   Optimized Durbin recursion.
   The algorithm is unchanged – the result is identical to the original.
   -------------------------------------------------------------------- */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Allocate scratch buffer once: we overwrite it each iteration.
    std::vector<double> z(n, 0.0);

    y[0] = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    // Main recursion
    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // Compute the dot product r[k-1-i] * y[i] for i=0..k-1
        double sum = 0.0;
        const double* __restrict__ r_p = r.data();
        const double* __restrict__ y_p = y.data();
        int i = 0;

        // Vectorised/unrolled loop
        #pragma omp simd reduction(+:sum) aligned(r_p,y_p:64)
        for (; i + 3 < k; i += 4) {
            sum += r_p[k - i - 1] * y_p[i];
            sum += r_p[k - i - 2] * y_p[i + 1];
            sum += r_p[k - i - 3] * y_p[i + 2];
            sum += r_p[k - i - 4] * y_p[i + 3];
        }
        for (; i < k; ++i)
            sum += r_p[k - i - 1] * y_p[i];

        alpha = -(r_p[k] + sum) / beta;

        // Update the first k elements of y in two passes:
        // 1) compute new values into z
        // 2) copy back to y
        i = 0;
        #pragma omp simd aligned(r_p,y_p,z.data():64)
        for (; i + 3 < k; i += 4) {
            z[i]     = y_p[i] + alpha * y_p[k - i - 1];
            z[i + 1] = y_p[i + 1] + alpha * y_p[k - i - 2];
            z[i + 2] = y_p[i + 2] + alpha * y_p[k - i - 3];
            z[i + 3] = y_p[i + 3] + alpha * y_p[k - i - 4];
        }
        for (; i < k; ++i)
            z[i] = y_p[i] + alpha * y_p[k - i - 1];

        // Copy back
        for (i = 0; i < k; ++i)
            y_p[i] = z[i];

        y_p[k] = alpha;
    }
}
