void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;
    const double inv_n = 1.0 / static_cast<double>(n);
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* ---------- mean ---------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) {
            s += data[i][j];
        }
        mean[j] = s * inv_n;
    }

    /* ---------- stddev ---------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        const double mv = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mv;
            s += d * d;
        }
        double tmp = std::sqrt(s * inv_n);
        stddev[j] = (tmp <= eps) ? 1.0 : tmp;
    }

    /* ---------- normalize data ---------- */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double v = data[i][j] - mean[j];
            v *= inv_sqrt_n / stddev[j];
            data[i][j] = v;
        }
    }

    /* ---------- correlation matrix ---------- */
    /* upper triangle + diagonal */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) {
                s += data[k][i] * data[k][j];
            }
            corr[i][j] = corr[j][i] = s;
        }
    }
