/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    // Work will be done in three phases for each k:
    //   1) compute R[k][k] (norm of column k)
    //   2) compute Q[:,k] = A[:,k] / R[k][k]
    //   3) for each j>k:
    //       - compute R[k][j] = <Q[:,k], A[:,j]>
    //       - update A[:,j] -= Q[:,k] * R[k][j]
    //
    // All of the loops over i (rows) are embarrassingly parallel
    // and can be distributed among the available threads.
    //
    // OpenMP pragmas are used to give the compiler knowledge of the
    // reductions and the fact that all iterations of an inner loop
    // are independent.
    //
    // The algorithm stays completely equivalent to the reference version.
    for (int k = 0; k < n; ++k) {
        double norm = 0.0;

        /* Phase 1: compute the norm of column k */
#pragma omp parallel for reduction(+:norm)
        for (int i = 0; i < m; ++i) {
            double val = A[i][k];
            norm += val * val;
        }
        R[k][k] = std::sqrt(norm);

        /* Phase 2: normalize column k to obtain Q[:,k] */
#pragma omp parallel for
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / R[k][k];
        }

        /* Phase 3: update remaining columns */
        for (int j = k + 1; j < n; ++j) {
            double rkj = 0.0;

            /* Compute the dot product of Q[:,k] and A[:,j] */
#pragma omp parallel for reduction(+:rkj)
            for (int i = 0; i < m; ++i) {
                rkj += Q[i][k] * A[i][j];
            }
            R[k][j] = rkj;

            /* Subtract the component of A[:,j] in the direction of Q[:,k] */
#pragma omp parallel for
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * rkj;
            }
        }
    }
}
