    const double inv9 = 1.0 / 9.0;
    const int n_minus_1 = n - 1;
    const int n_minus_2 = n - 2;

    /* Main time‑stepping loop. Each time step is performed in place
       on the flattened array.  */
    for (int t = 0; t < tsteps; ++t) {
        /* Parallelise over the interior rows; collapse prevents
           excessive scheduling overhead. */
#pragma omp parallel for schedule(static) collapse(1)
        for (int i = 1; i <= n_minus_2; ++i) {
            const int idx_i = i * n;
            const int idx_im1 = (i - 1) * n;
            const int idx_ip1 = (i + 1) * n;
            /* Unroll the inner loop to reduce loop‑overhead and
               increase register pressure.  */
            int j = 1;
            for (; j <= n_minus_2 - 3; j += 4) {
                const int offset = j;
                /* Indices for the current and neighbouring cells */
                const int idx_ij = idx_i + offset;
                const int idx_ij1 = idx_i + offset + 1;
                const int idx_ij2 = idx_i + offset + 2;
                const int idx_ij3 = idx_i + offset + 3;

                const double a00 = flat[idx_im1 + offset - 1];
                const double a01 = flat[idx_im1 + offset];
                const double a02 = flat[idx_im1 + offset + 1];
                const double a03 = flat[idx_im1 + offset + 2];
                const double a04 = flat[idx_im1 + offset + 3];

                const double a10 = flat[idx_i + offset - 1];
                const double a11 = flat[idx_i + offset];
                const double a12 = flat[idx_i + offset + 1];
                const double a13 = flat[idx_i + offset + 2];
                const double a14 = flat[idx_i + offset + 3];

                const double a20 = flat[idx_ip1 + offset - 1];
                const double a21 = flat[idx_ip1 + offset];
                const double a22 = flat[idx_ip1 + offset + 1];
                const double a23 = flat[idx_ip1 + offset + 2];
                const double a24 = flat[idx_ip1 + offset + 3];

                flat[idx_ij]     = (a00 + a01 + a02 + a10 + a11 + a12 + a20 + a21 + a22) * inv9;
                flat[idx_ij1]    = (a01 + a02 + a03 + a11 + a12 + a13 + a21 + a22 + a23) * inv9;
                flat[idx_ij2]    = (a02 + a03 + a04 + a12 + a13 + a14 + a22 + a23 + a24) * inv9;
                flat[idx_ij3]    = (a03 + a04 + a00 + a13 + a14 + a10 + a23 + a24 + a20) * inv9;
            }
            /* Handle the remaining columns that were not a multiple of 4 */
            for (; j <= n_minus_2; ++j) {
                const int idx_ij = idx_i + j;
                flat[idx_ij] = (flat[idx_im1 + j - 1] + flat[idx_im1 + j] + flat[idx_im1 + j + 1] +
                                flat[idx_i   + j - 1] + flat[idx_i   + j] + flat[idx_i   + j + 1] +
                                flat[idx_ip1 + j - 1] + flat[idx_ip1 + j] + flat[idx_ip1 + j + 1]) * inv9;
            }
        }
    }

    /* Copy the flattened data back to the original 2‑D vector. */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            A[i][j] = flat[i * n + j];
