/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Optimised via data layout, pre‑computed constants and OpenMP parallelism. */

void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* Flatten the 2‑D rows to 1‑D for better cache locality */
    const int wh = w * h;
    std::vector<float> in(wh), out(wh), tmp1(wh), tmp2(wh);
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            in[i*h + j] = imgIn[i][j];

    /* Pre‑computed constants (all floats for speed, same values as in original). */
    const float exp_a  = std::exp(-alpha);
    const float exp_2a = std::exp(-2.0f*alpha);
    const float k      = 1.0f - exp_a*(1.0f- exp_a) /
                          (1.0f + 2.0f*alpha*exp_a - exp_2a);
    const float a1 = a5 = k;
    const float a2 = a6 = k * exp_a * (alpha - 1.0f);
    const float a3 = a7 = k * exp_a * (alpha + 1.0f);
    const float a4 = a8 = -k * exp_2a;
    const float b1 = std::pow(2.0f, -alpha);
    const float b2 = -exp_2a;
    const float c  = 1.0f;   /* c1 and c2 are identical in the original code */

    /* ---------- First forward pass (row) ---------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        const int row = i * h;
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j, ++row) {
            float x = in[row];
            tmp1[row] = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = x;
            ym2 = ym1;
            ym1 = tmp1[row];
        }
    }

    /* ---------- Second reverse pass (row) ---------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        const int row = i * h;
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h - 1, idx = row + h - 1; j >= 0; --j, --idx) {
            float x = in[idx];
            tmp2[idx] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;
            xp1 = x;
            yp2 = yp1;
            yp1 = tmp2[idx];
        }
    }

    /* ---------- First forward pass (column) ---------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            float y = tmp1[i*h + j];
            int idx = i*h + j;
            tmp1[idx] = a5 * y + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = y;
            ym2 = ym1;
            ym1 = tmp1[idx];
        }
    }

    /* ---------- Second reverse pass (column) ---------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1, idx = (w-1)*h + j; i >= 0; --i, idx -= h) {
            float y = tmp2[idx];
            tm1 = tmp2[idx]; /* reuse temporary for input to the reverse col pass */
            tmp2[idx] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;
            tp1 = y;
            yp2 = yp1;
            yp1 = tmp2[idx];
        }
    }

    /* ---------- Combine and write output (row) ---------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        const int row = i * h;
        for (int j = 0; j < h; ++j, ++row) {
            out[row] = c * (tmp1[row] + tmp2[row]);
        }
    }

    /* ---------- Write back to the 2‑D output container ---------- */
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = out[i*h + j];
}
