/* Optimised kernel with contiguous memory usage and threaded loops.
 * The function signature is unchanged so it can be dropped directly
 * into the existing harness. */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    /* Flatten the 2‑D std::vector into a 1‑D contiguous array for
     * each input. The original layout is row‑major, so we keep the
     * same flattened layout: index = i*n + j where i is row. */
    const std::size_t N = static_cast<std::size_t>(n);
    const std::size_t NN = N * N;
    double* __restrict u_arr = reinterpret_cast<double*>(u.data());
    double* __restrict v_arr = reinterpret_cast<double*>(v.data());
    double* __restrict p_arr = reinterpret_cast<double*>(p.data());
    double* __restrict q_arr = reinterpret_cast<double*>(q.data());

    /* Pre‑compute constants */
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    /* Helper lambda for linear indexing */
    auto idx = [n](int i, int j) -> std::size_t { return static_cast<std::size_t>(i * n + j); };

    /* Main time loops */
    for (int t = 1; t <= tsteps; ++t)
    {
        /* ---- First sweep: compute v -------- */
        #pragma omp parallel for schedule(static) collapse(2)
        for (int i = 1; i < n - 1; ++i)
        {
            /* top/bottom rows of v for the current column */
            v_arr[idx(0, i)]     = 1.0;
            v_arr[idx(n-1, i)]   = 1.0;

            /* initialise first column of p and q for column i */
            p_arr[idx(i, 0)] = 0.0;
            q_arr[idx(i, 0)] = v_arr[idx(0, i)];

            /* forward pass (j = 1 .. n-2) */
            double denom;
            for (int j = 1; j < n - 1; ++j)
            {
                denom = a * p_arr[idx(i, j-1)] + b;
                p_arr[idx(i, j)] = -c / denom;
                const double term = (-d * u_arr[idx(j, i-1)] +
                                     (1.0 + 2.0 * d) * u_arr[idx(j, i)] -
                                     f * u_arr[idx(j, i+1)] -
                                     a * q_arr[idx(i, j-1)]);
                q_arr[idx(i, j)] = term / denom;
            }

            /* backward pass (j = n-2 .. 1) */
            for (int j = n-2; j >= 1; --j)
                v_arr[idx(j, i)] = p_arr[idx(i, j)] * v_arr[idx(j+1, i)] + q_arr[idx(i, j)];
        }

        /* ---- Second sweep: compute u -------- */
        #pragma omp parallel for schedule(static) collapse(2)
        for (int i = 1; i < n - 1; ++i)
        {
            /* left/right columns of u for the current row */
            u_arr[idx(i, 0)]     = 1.0;
            u_arr[idx(i, n-1)]   = 1.0;

            /* initialise first row of p and q for row i */
            p_arr[idx(i, 0)] = 0.0;
            q_arr[idx(i, 0)] = u_arr[idx(i, 0)];

            /* forward pass (j = 1 .. n-2) */
            double denom;
            for (int j = 1; j < n - 1; ++j)
            {
                denom = d * p_arr[idx(i, j-1)] + e;
                p_arr[idx(i, j)] = -f / denom;
                const double term = (-a * v_arr[idx(i-1, j)] +
                                     (1.0 + 2.0 * a) * v_arr[idx(i, j)] -
                                     c * v_arr[idx(i+1, j)] -
                                     d * q_arr[idx(i, j-1)]);
                q_arr[idx(i, j)] = term / denom;
            }

            /* backward pass (j = n-2 .. 1) */
            for (int j = n-2; j >= 1; --j)
                u_arr[idx(i, j)] = p_arr[idx(i, j)] * u_arr[idx(i, j+1)] + q_arr[idx(i, j)];
        }
    }
}
